import{_ as a,o as e,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"小动物-雪豹","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物-雪豹.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物-雪豹.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物-雪豹.md"};function o(d,b,_,l,i,c){return e(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"小动物-雪豹",tabindex:"-1"},[p("小动物-雪豹 "),r("a",{class:"header-anchor",href:"#小动物-雪豹","aria-label":'Permalink to "小动物-雪豹"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风022")])])],-1),n('<h1 id="小动物-雪豹-1" tabindex="-1">小动物-雪豹 <a class="header-anchor" href="#小动物-雪豹-1" aria-label="Permalink to &quot;小动物-雪豹&quot;">​</a></h1><p>雪豹<br> 无支线随从<br> 250分<br> 动物种类：猫科动物<br> 雪豹（学名：Panthera uncia），又名草豹、荷叶豹、艾叶豹，为食肉目猫科豹属的一种 。雪豹体型略小于普通豹，尾巴长度约为头体长度的3/4，相对长而粗大的尾巴是区分其与其他相似物种的显著特征。其头部小而圆，吻部较短，四肢相对较短。全身覆盖着长而密集的蓬松毛发，主要呈灰白色；背部和肋部散布着模糊或不规则的大型黑色环状斑块，并以五纵行的稀疏排列方式呈现，斑块内部点缀着小型斑点；头部、颈部及四肢下方可见成行排列的黑色圆形斑点；臀部上方，五个黑色斑点纵向排列成一条醒目的黑色条纹。<br> 随从外貌：你可以选择一种毛色和条纹，然后填写在这里，一般情况下雪豹基础外貌跟百科其实差不多。<br> 基础外貌：3<br> 基础体型：3-5</p><p>随从属性：<br> 生理属性<br> 力量：5<br> 敏捷：5<br> 耐力：3<br> 心智属性<br> 智力：1<br> 感知：3<br> 决心：1<br> 互动属性<br> 风度：3<br> 操控：1<br> 沉着：1</p><p>技能<br> 生理系<br> 运动3<br> 专业：反射3 跳跃1<br> 求生1<br> 专业：强韧1<br> 射击1<br> 专业：<br> 武技1<br> 专业：爪击1</p><p>心智系<br> 学识1<br> 专业：爪子精通1<br> 器用1<br> 专业：<br> 手艺1<br> 专业：<br> 专注1<br> 专业：意志1</p><p>互动系<br> 洞察3<br> 专业：侦查3<br> 隐秘1<br> 专业：<br> 表达1<br> 专业：<br> 社交1<br> 专业</p><p>衍生属性值<br> 体积<br> 速度 （力量【5】+敏捷【5】+体积【3-5】+每1点敏捷上的附加获得3移动速度）=13-15<br> 先攻 （敏捷【5】+沉着【1】）= 6<br> 防御 （敏捷感知的平均值【4】+较高者的附加成功【】）=4<br> 生命值 （耐力【3】+体积【3-5】+耐力附加【 】×5）=6-8<br> 意志力池 （决心【1】+沉着【1】+决心附加【 】×2）=2<br> 意志 （决心【1】+专注+意志【2】）= 3<br> 反射 （敏捷【5】+运动+反射【6】）= 11+1<br> 强韧 （耐力【3】+生存+强韧【2】）= 5<br> 侦查 （感知【3】+洞察+侦查【6】）= 9+1<br> 敏感范围 （感知【3】*20米+感知上的附加成功【 】*20米）=60米</p><p>攻击预设：4<br> 基础DP：1（力量）+1（武技）+1（爪击）+1（爪子精通）=4<br> 非常态项：<br> 破防效果：<br> 附加成功：<br> 非常态项：<br> 攻击特殊效果：</p><p>防御预设：<br> 基础防御：4<br> 附加成功：无<br> 额外效果：<br> 防御类型：<br> 附加成功：<br> 额外效果：</p><p>豁免项：<br> 意志豁免：3<br> 附加成功：<br> 反射豁免：11<br> 附加成功：1<br> 强韧豁免：5<br> 附加成功：</p><p>免疫项：</p><p>专长：</p><p>装备位：<br> 头部-面具/头盔（会被雪豹带在头上但是因为脸部无法带面具所以一般面具无法佩戴）<br> 颈部-护符 （会变成项链吊坠项圈这种在雪豹的身上）<br> 上肢-躯干 （会被当做衣服穿在雪豹的身上）<br> 肩部-斗篷 （会在脖子上，但是会跟颈部装备产生冲突）<br> 上肢-爪子 （给爪子上特殊的武装，但是不能持握武器）<br> 手部-手腕 （给雪豹的四条腿上挂上腕带类似，戴上一个可以选择四条腿都有一样的画风，但是依旧只有一个装备位）<br> 下肢-鞋袜 （给雪豹的爪子穿上鞋袜但是因此会跟爪子产生冲突）</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
